VALUES
  ('disabled-57f41407-moex-00356', 'disabled-57f41407', 'disabled-57f41407-moex-112-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於送達，下列敘述何者正確？', '["當事人有「應為送達之處所不明或無故拒不收受送達」之情形者，法院 應依職權裁定公示送達", "應受送達人拒絕收領而無法律上理由者，應將文書置於送達處所，以為 送達", "送達於住居所不獲會晤應受送達人時，不得將文書交付與當事人之同居 人或受僱人", "支付命令之送達，法院得依聲請而為公示送達"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "1de48eae2baf", "answer_pdf_sha1": "b2f2ec6bc560", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00357', 'disabled-57f41407', 'disabled-57f41407-moex-112-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於言詞辯論期日通知書之送達，下列何者，不生送達之效力？', '["甲公司為商業訴訟之當事人，書記官將通知書送達於甲之經理人乙", "甲公司委任律師乙為訴訟代理人，乙之受送達權限未受限制，書記官得 逕將通知書送達於甲公司", "當事人甲指定送達代收人乙，向受訴法院陳明，書記官送達於乙，然而 乙未將通知書及時轉交給甲本人", "送達於當事人甲之住居所，不獲會晤甲，書記官將通知書付與甲之同居 人乙，乙有辨別事理之能力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "1de48eae2baf", "answer_pdf_sha1": "b2f2ec6bc560", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00358', 'disabled-57f41407', 'disabled-57f41407-moex-112-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於言詞辯論與筆錄記載，下列敘述何者正確？', '["當事人或關係人對於筆錄之記載有異議者，應聲請法院書記官以裁定更 正之", "筆錄內應記載當事人對訴訟標的之捨棄、認諾或自認事項。但兩造當事 人均委任訴訟代理人者，得以書面合意無須記載前開事項", "關於言詞辯論所定程式之遵守，專以筆錄證之", "證人均須於言詞辯論期日到場為言詞陳述，不得以文書代之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "1de48eae2baf", "answer_pdf_sha1": "b2f2ec6bc560", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00359', 'disabled-57f41407', 'disabled-57f41407-moex-112-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '下列何者為處分權主義之範圍？', '["甲於對乙基於侵權行為損害賠償之訴訟中，是否提出證據證明乙為侵權 行為之加害人", "甲於訴訟進行中是否撤回起訴", "關於被告乙是否具有訴訟能力", "被告乙對於原告之主張是否提出時效抗辯"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "1de48eae2baf", "answer_pdf_sha1": "b2f2ec6bc560", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00360', 'disabled-57f41407', 'disabled-57f41407-moex-112-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '甲對乙有二債權，一為借款新臺幣（下同）100 萬元，訴訟管轄法院為 A 地方法院；一為工程款120萬元，訴訟管轄法院為B地方法院。下列敘述 何者錯誤？', '["甲得分別向 A 法院起訴請求清償該借款、向 B 法院起訴請求給付該工 程款", "甲得向A法院合併起訴請求清償該借款及給付該工程款", "甲得僅向B法院起訴請求給付該工程款", "甲不得向B法院合併起訴請求清償該借款及給付該工程款"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "1de48eae2baf", "answer_pdf_sha1": "b2f2ec6bc560", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00361', 'disabled-57f41407', 'disabled-57f41407-moex-112-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '下列期間之遲誤，何者得聲請回復原狀？', '["證人請求日費之期間", "抗告期間", "聲請退還裁判費之期間", "裁定命補正裁判費之期間"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "1de48eae2baf", "answer_pdf_sha1": "b2f2ec6bc560", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00362', 'disabled-57f41407', 'disabled-57f41407-moex-112-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於訴訟上和解，下列敘述何者正確？', '["法院於進行言詞辯論前，得隨時試行和解", "當事人雖有和解之望，然而一造到場有困難時，法院仍不得依另一造當 事人之聲請提出和解方案", "和解成立後，一造當事人不履行時，他造得請求繼續審判", "和解成立者，與確定判決有同一之效力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "1de48eae2baf", "answer_pdf_sha1": "b2f2ec6bc560", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00363', 'disabled-57f41407', 'disabled-57f41407-moex-112-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '調解程序中，下列何種情形，法院得以裁定處新臺幣3,000元以下之罰鍰？', '["當事人有代理人，經法院命本人到場而無正當理由不到場", "應表明為調解標的之法律關係及爭議而未表明", "有文書為證據者，未提出其原本", "前已經其他法定調解機關調解未成立而再聲請調解"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "1de48eae2baf", "answer_pdf_sha1": "b2f2ec6bc560", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00364', 'disabled-57f41407', 'disabled-57f41407-moex-112-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '適用簡易訴訟事件之第一審程序，應在何人之前行之？', '["合議庭法官3人", "獨任法官1人", "司法事務官1人", "合議庭之審判長及受命法官各1人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "1de48eae2baf", "answer_pdf_sha1": "b2f2ec6bc560", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00365', 'disabled-57f41407', 'disabled-57f41407-moex-112-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '下列何者，一律不得適用小額訴訟程序？', '["請求給付法定貨幣", "請求給付稻穀", "請求返還占用土地", "請求返還支票"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "1de48eae2baf", "answer_pdf_sha1": "b2f2ec6bc560", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
